Actionscript.script:
stop();

import flash.events.MouseEvent;
import flash.display.MovieClip;

if (Object(this).skorTotalGame == undefined) {
    Object(this).skorTotalGame = 0; 
}

txt_timer.background = false; txt_timer.border = false;
txt_poinangka.background = false; txt_poinangka.border = false;
txt_pointext.background = false; txt_pointext.border = false;

txt_poinangka.text = String(Object(this).skorTotalGame);

// 1. Setup Teks Soal (Ubah < dan > menjadi &lt; dan &gt; agar aman di mode HTML)
var soalAsli:String = "#include &lt;iostream&gt;\nusing namespace std;\n\nint main() {\n  // Tampilkan teks ke layar\n  [ Zona 1 ] &lt;&lt; \"Halo, C++!\";\n  return 0;\n}";

// Tampilkan soal original menggunakan mode HTML
txt_soal.htmlText = soalAsli; 

// 2. Setup Kunci Jawaban
var jawabanBenarDTB:String = "btn_jawaban2"; 
var jawabanPemain:MovieClip = null;

// 3. Setup Interaksi Balok & Nilai Teksnya
this.btn_jawaban1.nilaiTeks = "cin";
this.btn_jawaban2.nilaiTeks = "cout";
this.btn_jawaban3.nilaiTeks = "get";
this.btn_jawaban4.nilaiTeks = "print";

for (var indexBlok:int = 1; indexBlok <= 4; indexBlok++) {
    var btn:MovieClip = this["btn_jawaban" + indexBlok] as MovieClip;
    btn.buttonMode = true;

    btn.startX = btn.x;
    btn.startY = btn.y;

    btn.addEventListener(MouseEvent.MOUSE_DOWN, ambilBlok);
    btn.addEventListener(MouseEvent.MOUSE_UP, lepasBlok);
}

btn_lanjutdtb.buttonMode = true;
btn_lanjutdtb.addEventListener(MouseEvent.CLICK, cekSkorDTB);

// 4. Mekanik Drag
function ambilBlok(e:MouseEvent):void {
    var blok:MovieClip = e.currentTarget as MovieClip;
    setChildIndex(blok, numChildren - 1); 
    blok.startDrag();
}

// 5. Mekanik Drop & Ganti Teks dengan Warna MERAH
function lepasBlok(e:MouseEvent):void {
    var blok:MovieClip = e.currentTarget as MovieClip;
    blok.stopDrag();

    if (blok.hitTestObject(dropZone)) {

        blok.x = dropZone.x + (dropZone.width / 2) - (blok.width / 2);
        blok.y = dropZone.y + (dropZone.height / 2) - (blok.height / 2);

        jawabanPemain = blok; 

        // --- FITUR WARNA MERAH ---
        // Kita bungkus nilai teksnya dengan tag HTML warna merah (#FF0000)
        var teksMerah:String = "<font color='#FF0000'>" + blok.nilaiTeks + "</font>";

        // Ganti "[ Zona 1 ]" dengan teks yang sudah diwarnai merah
        txt_soal.htmlText = soalAsli.replace("[ Zona 1 ]", teksMerah);

        for (var j:int = 1; j <= 4; j++) {
            var btnLain:MovieClip = this["btn_jawaban" + j] as MovieClip;
            if (btnLain != blok) {
                btnLain.x = btnLain.startX;
                btnLain.y = btnLain.startY;
            }
        }

    } else {
        blok.x = blok.startX;
        blok.y = blok.startY;

        if (jawabanPemain == blok) {
            jawabanPemain = null; 
            // Kembalikan soal ke bentuk originalnya (tanpa warna merah)
            txt_soal.htmlText = soalAsli; 
        }
    }
}

// 6. Validasi Skor 
function cekSkorDTB(e:MouseEvent):void {
    if (jawabanPemain != null) {

        if (jawabanPemain.name == jawabanBenarDTB) {
            Object(this).skorTotalGame += 25; 
            txt_poinangka.text = String(Object(this).skorTotalGame);
        }

        gotoAndStop(1, "Skor"); 

    } else {
        trace("Belum dijawab");
    }
}

stop();

import flash.events.MouseEvent;
import flash.display.Shape;
import flash.display.MovieClip;

txt_timer.background = false; txt_timer.border = false;
txt_poinangka.background = false; txt_poinangka.border = false;
txt_pointext.background = false; txt_pointext.border = false;

// Variabel Global
var skorTotalGame:int = 0;
var gameSelesai:Boolean = false;
var startX:Number;
var startY:Number;
var activeBlock:MovieClip;
var activeIndex:int;

// 1. Membuat Wadah Garis
var lines:Array = [];
var indexGaris:int;

for (indexGaris = 1; indexGaris <= 4; indexGaris++) {
    var line:Shape = new Shape();
    addChild(line);
    lines[indexGaris] = line;
}

// 2. KAMUS JAWABAN UNTUK 5 LEVEL
// Index 0 dikosongkan agar Index 1 = Frame 1, Index 2 = Frame 2, dst.
var semuaKunci:Array = [
    null,
    // Kunci Frame 1 
    { "btnkiri1":"btnkanan4", "btnkiri2":"btnkanan3", "btnkiri3":"btnkanan1", "btnkiri4":"btnkanan2" },
    // Kunci Frame 2 (Silakan sesuaikan)
    { "btnkiri1":"btnkanan1", "btnkiri2":"btnkanan2", "btnkiri3":"btnkanan3", "btnkiri4":"btnkanan4" },
    // Kunci Frame 3
    { "btnkiri1":"btnkanan2", "btnkiri2":"btnkanan4", "btnkiri3":"btnkanan1", "btnkiri4":"btnkanan3" },
    // Kunci Frame 4
    { "btnkiri1":"btnkanan3", "btnkiri2":"btnkanan1", "btnkiri3":"btnkanan4", "btnkiri4":"btnkanan2" },
    // Kunci Frame 5
    { "btnkiri1":"btnkanan4", "btnkiri2":"btnkanan2", "btnkiri3":"btnkanan3", "btnkiri4":"btnkanan1" }
];

// 3. FUNGSI SETUP LEVEL (Dijalankan setiap pindah frame)
function setupLevel():void {
    gameSelesai = false;

    // Tembakkan skor tersimpan ke instance text UI
    txt_poinangka.text = String(skorTotalGame); 

    for (var j:int = 1; j <= 4; j++) {
        lines[j].graphics.clear(); 

        var btn:MovieClip = this["btnkiri" + j] as MovieClip;
        if (btn != null) {
            btn.buttonMode = true;
            btn.index = j;
            btn.connectedTo = null; 

            btn.removeEventListener(MouseEvent.MOUSE_DOWN, onDragStart);
            btn.addEventListener(MouseEvent.MOUSE_DOWN, onDragStart);
        }
    }

    btn_lanjutctd.removeEventListener(MouseEvent.CLICK, onLanjutClick);
    btn_lanjutctd.addEventListener(MouseEvent.CLICK, onLanjutClick);
}

// 4. LOGIKA DRAG & DROP
function onDragStart(e:MouseEvent):void {
    if (gameSelesai) return; 
    activeBlock = e.currentTarget as MovieClip;
    activeIndex = activeBlock.index;
    startX = activeBlock.x + activeBlock.width;
    startY = activeBlock.y + (activeBlock.height / 2);

    stage.addEventListener(MouseEvent.MOUSE_MOVE, onDragging);
    stage.addEventListener(MouseEvent.MOUSE_UP, onDragDrop);
}

function onDragging(e:MouseEvent):void {
    var currentLine:Shape = lines[activeIndex];
    currentLine.graphics.clear();
    currentLine.graphics.lineStyle(5, 0x3399FF); // Garis ditarik (Biru Muda)
    currentLine.graphics.moveTo(startX, startY);
    currentLine.graphics.lineTo(mouseX, mouseY);
}

function onDragDrop(e:MouseEvent):void {
    stage.removeEventListener(MouseEvent.MOUSE_MOVE, onDragging);
    stage.removeEventListener(MouseEvent.MOUSE_UP, onDragDrop);

    var currentLine:Shape = lines[activeIndex];
    var isConnected:Boolean = false;

    for (var k:int = 1; k <= 4; k++) {
        var targetBtn:MovieClip = this["btnkanan" + k] as MovieClip;
        if (targetBtn.hitTestPoint(mouseX, mouseY, true)) {
            var targetX:Number = targetBtn.x; 
            var targetY:Number = targetBtn.y + (targetBtn.height / 2);

            currentLine.graphics.clear();
            currentLine.graphics.lineStyle(5, 0x297ACC); // Garis nempel (Biru Tua)
            currentLine.graphics.moveTo(startX, startY);
            currentLine.graphics.lineTo(targetX, targetY);

            activeBlock.connectedTo = targetBtn.name;
            isConnected = true;
            break; 
        }
    }
    if (!isConnected) {
        currentLine.graphics.clear();
        activeBlock.connectedTo = null;
    }
}

// 5. PENILAIAN LANGSUNG & PINDAH FRAME
function onLanjutClick(e:MouseEvent):void {
    if (gameSelesai) return;

    var skorLevelIni:int = 0;
    var kunciSekarang:Object = semuaKunci[currentFrame];

    // Periksa jawaban secara gaib
    for (var m:int = 1; m <= 4; m++) {
        var kiri:MovieClip = this["btnkiri" + m] as MovieClip;
        if (kiri.connectedTo != null) {
            if (kiri.connectedTo == kunciSekarang[kiri.name]) {
                skorLevelIni += 25; 
            }
        }
    }

    // Update perhitungan skor dan tembak lagi ke UI
    skorTotalGame += skorLevelIni; 
    txt_poinangka.text = String(skorTotalGame);

    if (currentFrame < 5) {
        gotoAndStop(currentFrame + 1); 
    } else {
        trace("GAME TAMAT! SKOR AKHIR: " + skorTotalGame);
        gameSelesai = true; 
    }
}

// Panggil fungsi pertama kali
setupLevel();

setupLevel();

txt_timer.background = false; txt_timer.border = false;
txt_poinangka.background = false; txt_poinangka.border = false;
txt_pointext.background = false; txt_pointext.border = false;

setupLevel();

txt_timer.background = false; txt_timer.border = false;
txt_poinangka.background = false; txt_poinangka.border = false;
txt_pointext.background = false; txt_pointext.border = false;

setupLevel();

txt_timer.background = false; txt_timer.border = false;
txt_poinangka.background = false; txt_poinangka.border = false;
txt_pointext.background = false; txt_pointext.border = false;

setupLevel();

txt_timer.background = false; txt_timer.border = false;
txt_poinangka.background = false; txt_poinangka.border = false;
txt_pointext.background = false; txt_pointext.border = false;
